from lxml import etree
from io import StringIO
import re
from django.http import HttpResponse


def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    # Get parameters from GET request
    xpath_value = request.GET.get('xpath', '')
    xml_value = request.GET.get('xml', '')

    # Validate xpath_value - only allow numeric values to prevent XPath injection
    if not re.match(r'^\d+$', xpath_value):
        return HttpResponse('Invalid xpath parameter', status=400)

    # Construct the XPath query
    xpath_query_str = f"/tag[@id={xpath_value}]"

    try:
        # Parse the XML safely
        parser = etree.XMLParser()
        root = etree.parse(StringIO(xml_value), parser)

        # Execute the XPath query
        result = root.xpath(xpath_query_str)

        # Convert result to string representation
        if result:
            if isinstance(result, list):
                if len(result) == 1:
                    return HttpResponse(str(result[0]))
                else:
                    return HttpResponse(str([etree.tostring(elem, encoding='unicode') for elem in result]))
            else:
                return HttpResponse(str(result))
        else:
            return HttpResponse('No results found', status=404)

    except etree.XMLSyntaxError:
        return HttpResponse('Invalid XML', status=400)
    except Exception as e:
        return HttpResponse(f'Error: {str(e)}', status=500)
